export const findCourse = (id) => COURSES.find((c) => c.id === id);
export const findLesson = (course, lid) => course && course.lessons.find((l) => l.id === lid);

/* ------------------------------------------------------------ lazy loading */
const loading = new Map(); // courseId -> Promise, so concurrent callers share one fetch
const loaded = new Set();

/** True once a course's words are in memory. Callers that prune stale progress
 *  MUST check this first — an unloaded course has no items, not zero items. */
export const courseLoaded = (id) => loaded.has(id);

/** Pull in one course's vocabulary and merge it into the metadata objects.
 *  Idempotent and safe to call from several places at once. */
export function loadCourse(id) {
  if (loaded.has(id)) return Promise.resolve(findCourse(id));
  if (loading.has(id)) return loading.get(id);
  const course = findCourse(id);
  if (!course) return Promise.resolve(null);
  const p = import(`./data/${id}.js`)
    .then((mod) => {
      const byLesson = mod.default || {};
      for (const l of course.lessons) {
        const items = byLesson[l.id];
        if (items) l.items = items;
      }
      loaded.add(id);
      loading.delete(id);
      return course;
    })
    .catch((err) => {
      loading.delete(id);
      throw err;
    });
  loading.set(id, p);
  return p;
}

/** Load several courses at once; unknown ids are ignored. */
export function loadCourses(ids) {
  return Promise.all([...new Set(ids)].filter(Boolean).map((id) => loadCourse(id).catch(() => null)));
}

/** Load the whole catalogue — only the dictionary really needs this. */
export function loadAll() {
  return loadCourses(COURSES.map((c) => c.id));
}
